import React, { useEffect, useState } from 'react';
import axios from 'axios';
import BlogCard from '../components/BlogCard';
import { useNavigate } from 'react-router-dom';

const HomePage = () => {
  const [blogs, setBlogs] = useState([]);
  const [categories, setCategories] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const navigate = useNavigate();

  const isAdmin = localStorage.getItem('role') === 'admin';

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [blogsRes, categoriesRes] = await Promise.all([
          axios.get('http://localhost:5000/api/blogs'),
          axios.get('http://localhost:5000/api/categories'),
        ]);
        console.log('Fetched blogs:', blogsRes.data);
        console.log('Fetched categories:', categoriesRes.data);
        setBlogs(blogsRes.data);
        setCategories(categoriesRes.data);
        setLoading(false);
      } catch (err) {
        console.error('Error fetching data:', err);
        setError('Failed to load data.');
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  const handleDelete = async (id) => {
    try {
      await axios.delete(`${process.env.REACT_APP_API_BASE_URL}/blogs/${id}`);

      setBlogs(prev => prev.filter(blog => blog.id !== id));
    } catch (err) {
      console.error('Error deleting blog:', err);
      alert('Failed to delete blog.');
    }
  };

  // Use fallback key in case 'category_name' is missing
  const filteredBlogs =
    selectedCategory === 'All'
      ? blogs
      : blogs.filter((blog) =>
          (blog.category_name || blog.category) === selectedCategory
        );

  return (
    <div className="p-4">
      {loading && <p className="text-center text-gray-600 mt-8">Loading blogs...</p>}
      {error && <p className="text-center text-red-600 mt-8">{error}</p>}

      {!loading && !error && (
        <>
          {/* Category Filter */}
          <div className="flex flex-wrap gap-3 mb-6 justify-center">
            <button
              onClick={() => setSelectedCategory('All')}
              className={`px-4 py-1 rounded-full ${selectedCategory === 'All' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}
            >
              All
            </button>
            {categories.map((category) => (
              <button
                key={category.id}
                onClick={() => setSelectedCategory(category.name)}
                className={`px-4 py-1 rounded-full ${
                  selectedCategory === category.name ? 'bg-blue-600 text-white' : 'bg-gray-200'
                }`}
              >
                {category.name}
              </button>
            ))}
          </div>

          {/* Blog Cards */}
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {filteredBlogs.length > 0 ? (
              filteredBlogs.map((blog) => (
                <BlogCard
                  key={blog.id}
                  blog={blog}
                  isAdmin={isAdmin}
                  onEdit={() => navigate(`/edit-blog/${blog.id}`)}
                  onDelete={() => handleDelete(blog.id)}
                />
              ))
            ) : (
              <p className="col-span-full text-center text-gray-500">
                No blogs found in this category.
              </p>
            )}
          </div>
        </>
      )}
    </div>
  );
};

export default HomePage;
